-- Params add-on session table (add-on id "params" -> PARAMS_* RDBMS naming for DataNucleus/HSQL).
-- Migrates legacy core table PARAM into PARAMS_PARAM, then drops PARAM.
-- If PARAM is missing, create a matching stub so the copy runs without procedure/EXECUTE tricks.
-- Copy runs only when PARAM has rows, avoiding HSQL "no data" (02000/-1100) on empty INSERT...SELECT.

CREATE CACHED TABLE IF NOT EXISTS "PARAMS_PARAM" (
    "PARAMID" BIGINT GENERATED BY DEFAULT AS IDENTITY (START WITH 1) PRIMARY KEY,
    "SITE" VARCHAR(32768) NOT NULL,
    "TYPE" VARCHAR(32768) NOT NULL,
    "NAME" VARCHAR(32768) NOT NULL,
    "USED" INTEGER NOT NULL,
    "FLAGS" VARCHAR(32768) NOT NULL,
    "VALS" VARCHAR(8388608) NOT NULL
);

CREATE CACHED TABLE IF NOT EXISTS PARAM (
    PARAMID BIGINT GENERATED BY DEFAULT AS IDENTITY (START WITH 1),
    SITE VARCHAR(32768) NOT NULL,
    TYPE VARCHAR(32768) NOT NULL,
    NAME VARCHAR(32768) NOT NULL,
    USED INT NOT NULL,
    FLAGS VARCHAR(32768) NOT NULL,
    VALS VARCHAR(8388608) NOT NULL
);

CREATE PROCEDURE PARAMS_MIGRATE_COPY_FROM_PARAM() MODIFIES SQL DATA
BEGIN ATOMIC
 IF (SELECT COUNT(*) FROM "PARAM") > 0 THEN
  INSERT INTO "PARAMS_PARAM" ("SITE","TYPE","NAME","USED","FLAGS","VALS")
  SELECT "SITE","TYPE","NAME","USED","FLAGS","VALS" FROM "PARAM";
 END IF;
END;

CALL PARAMS_MIGRATE_COPY_FROM_PARAM();

DROP PROCEDURE PARAMS_MIGRATE_COPY_FROM_PARAM;

DROP TABLE IF EXISTS "PARAM";
